import React, { useMemo, useState } from "react";
import GraphvizViewer from "./GraphvizViewer";
import { runDfaTrace } from "../utils/automataView";

export function TransitionTable({ transitions }) {
  if (!transitions || transitions.length === 0) {
    return <p className="empty-message">No transitions available.</p>;
  }

  return (
    <div className="table-wrap">
      <table>
        <thead>
          <tr>
            <th>From</th>
            <th>Symbol</th>
            <th>To</th>
          </tr>
        </thead>
        <tbody>
          {transitions.map(([from, symbol, to], idx) => (
            <tr key={`${from}-${symbol}-${to}-${idx}`}>
              <td>{from}</td>
              <td>{symbol}</td>
              <td>{to}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export function TupleView({ tupleData }) {
  if (!tupleData) {
    return null;
  }

  return (
    <div className="text-block tuple-block">
      <p>
        <strong>Q:</strong> {`{${(tupleData.Q || []).join(", ")}}`}
      </p>
      <p>
        <strong>Σ:</strong> {`{${(tupleData.Sigma || []).join(", ")}}`}
      </p>
      <p>
        <strong>q0:</strong> {tupleData.q0}
      </p>
      <p>
        <strong>F:</strong> {`{${(tupleData.F || []).join(", ")}}`}
      </p>
      <p>
        <strong>δ:</strong> listed in transition table below
      </p>
    </div>
  );
}

export function StageCard({ title, subtitle, graph, tuple, compactGraph = false }) {
  if (!graph) {
    return null;
  }

  return (
    <section className="card stage-card">
      <h2>{title}</h2>
      <p>{subtitle}</p>
      <TupleView tupleData={tuple} />
      <TransitionTable transitions={graph.transitions} />
      <GraphvizViewer
        title={title}
        transitions={graph.transitions}
        start={graph.start}
        finalStates={graph.final}
        compact={compactGraph}
      />
    </section>
  );
}

export function DfaStateMapping({ rows, formatSubset }) {
  if (!rows || rows.length === 0) {
    return null;
  }

  return (
    <section className="card state-subset-card">
      <h2>DFA State Mapping</h2>
      <p>Each DFA state corresponds to a subset of NFA states.</p>
      <div className="table-wrap">
        <table>
          <thead>
            <tr>
              <th>DFA State</th>
              <th>NFA Subset</th>
            </tr>
          </thead>
          <tbody>
            {rows.map((item) => (
              <tr key={item.dfaState}>
                <td>{item.dfaState}</td>
                <td>{formatSubset(item.nfaSubset)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
}

export function DfaBuildSimulator({ steps }) {
  const [cursor, setCursor] = useState(0);

  React.useEffect(() => {
    setCursor(0);
  }, [steps]);

  if (!steps || steps.length === 0) {
    return null;
  }

  const current = steps[Math.min(cursor, steps.length - 1)];

  return (
    <section className="card dfa-build-card">
      <h2>NFA to DFA Construction Simulator</h2>
      <p>Click through the subset construction steps. No auto-play, just clear state formation.</p>

      <div className="simulator-controls dfa-build-controls">
        <button
          type="button"
          className="secondary"
          onClick={() => {
            setCursor(0);
          }}
        >
          Reset
        </button>
        <button
          type="button"
          className="secondary"
          disabled={cursor === 0}
          onClick={() => {
            setCursor((prev) => Math.max(prev - 1, 0));
          }}
        >
          Prev
        </button>
        <button
          type="button"
          disabled={cursor >= steps.length - 1}
          onClick={() => {
            setCursor((prev) => Math.min(prev + 1, steps.length - 1));
          }}
        >
          Next
        </button>
      </div>

      <div className="text-block">
        <p>
          <strong>Step:</strong> {cursor + 1} / {steps.length}
        </p>
        <p>
          <strong>From subset:</strong> {current.from_label}
        </p>
        <p>
          <strong>Input symbol:</strong> {current.symbol}
        </p>
        <p>
          <strong>To subset:</strong> {current.to_label}
        </p>
        <p>
          <strong>New state:</strong> {current.is_new ? "Yes" : "No"}
        </p>
      </div>

      <div className="step-visual-strip">
        {(steps.slice(0, cursor + 1) || []).map((step, index) => (
          <div key={`${step.from_label}-${step.symbol}-${index}`} className={`step-bubble ${index === cursor ? "active" : "done"}`}>
            <span className="step-bubble-index">{index + 1}</span>
            <span className="step-bubble-label">{step.to_label}</span>
            <span className="step-bubble-meta">on {step.symbol}</span>
          </div>
        ))}
      </div>

      <div className="table-wrap">
        <table>
          <thead>
            <tr>
              <th>#</th>
              <th>From Subset</th>
              <th>Symbol</th>
              <th>To Subset</th>
              <th>New?</th>
            </tr>
          </thead>
          <tbody>
            {steps.map((step, index) => (
              <tr key={`${step.from_label}-${step.symbol}-${index}`} className={index === cursor ? "active-row" : ""}>
                <td>{index + 1}</td>
                <td>{step.from_label}</td>
                <td>{step.symbol}</td>
                <td>{step.to_label}</td>
                <td>{step.is_new ? "Yes" : "No"}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
}

export function DfaStringSimulator({ dfa }) {
  const [input, setInput] = useState("");
  const [result, setResult] = useState(null);

  const alphabet = useMemo(() => {
    return Array.from(new Set((dfa?.transitions || []).map(([, symbol]) => symbol))).sort();
  }, [dfa]);

  React.useEffect(() => {
    setInput("");
    setResult(null);
  }, [dfa]);

  const onRun = () => {
    const traceResult = runDfaTrace(dfa, input.trim());
    setResult(traceResult);
  };

  if (!dfa) {
    return null;
  }

  return (
    <section className="card simulator-card">
      <h2>DFA String Simulator</h2>
      <p>Run strings over the generated DFA and inspect the state path.</p>

      <div className="simulator-controls">
        <input
          value={input}
          onChange={(event) => setInput(event.target.value)}
          placeholder={`Try string over alphabet: ${alphabet.join(", ") || "-"}`}
        />
        <button type="button" onClick={onRun}>
          Run String
        </button>
      </div>

      {result && (
        <div className={`sim-output ${result.accepted ? "accepted" : "rejected"}`}>
          <p>
            <strong>{result.accepted ? "Accepted" : "Rejected"}</strong>
          </p>
          <p>{result.reason}</p>
          <p>
            End state: <strong>{result.endState || "-"}</strong>
          </p>

          {result.trace.length > 0 && (
            <div className="trace-list">
              {result.trace.map((row) => (
                <div key={`${row.step}-${row.from}-${row.symbol}`} className="trace-item">
                  <span>#{row.step}</span>
                  <span>{row.from}</span>
                  <span>--{row.symbol}--&gt;</span>
                  <span>{row.to}</span>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </section>
  );
}
